(function () {
  function addStyle() { if (document.getElementById('bdv-style')) return; var s = document.createElement('style'); s.id = 'bdv-style'; s.textContent = '.bdv-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.bdv-controls{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.bdv-chart{height:250px;border:1px solid #e5e7eb;border-radius:12px;background:#f8fafc;display:flex;align-items:flex-end;gap:4px;padding:12px;position:relative;margin:12px 0}.bdv-bar{flex:1;background:#007bff;border-radius:6px 6px 0 0;min-width:8px;position:relative}.bdv-bar.hot{background:#ffc107}.bdv-bar span{position:absolute;bottom:-22px;left:50%;transform:translateX(-50%);font-size:11px}.bdv-line{position:absolute;bottom:12px;top:12px;width:3px;background:#dc3545}.bdv-out{padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.bdvMounted) return; host.dataset.bdvMounted = '1'; addStyle(); host.innerHTML = '<div class="bdv-wrap"><h4>📊 Phân phối nhị thức</h4><div class="bdv-controls"><label>n: <span data-nv>10</span><input data-n type="range" min="1" max="20" value="10"></label><label>p: <span data-pv>0.5</span><input data-p type="range" min="0.1" max="0.9" step="0.1" value="0.5"></label><label>k cần tính<input data-k type="number" min="0" value="5"></label></div><button type="button" data-draw>Vẽ phân phối</button><div class="bdv-chart"></div><div class="bdv-out"></div></div>'; var chart = host.querySelector('.bdv-chart'), out = host.querySelector('.bdv-out'); function C(n,k){var r=1; for(var i=1;i<=k;i++) r=r*(n-k+i)/i; return r;} function P(n,p,k){return C(n,k)*Math.pow(p,k)*Math.pow(1-p,n-k);} function draw(){var n=+host.querySelector('[data-n]').value,p=+host.querySelector('[data-p]').value,k=Math.max(0,Math.min(n,+host.querySelector('[data-k]').value||0)); host.querySelector('[data-nv]').textContent=n; host.querySelector('[data-pv]').textContent=p.toFixed(1); host.querySelector('[data-k]').max=n; host.querySelector('[data-k]').value=k; var ps=[]; for(var i=0;i<=n;i++) ps.push(P(n,p,i)); var m=Math.max.apply(null,ps), mean=n*p; chart.innerHTML=ps.map(function(v,i){return '<div class="bdv-bar'+(i===k?' hot':'')+'" style="height:'+(180*v/m+8)+'px" title="P(X='+i+')='+v.toFixed(4)+'"><span>'+i+'</span></div>';}).join('')+'<div class="bdv-line" style="left:calc(12px + '+(mean/n*100)+'% - 2px)" title="E[X]"></div>'; out.innerHTML='P(X='+k+') = C('+n+','+k+')·'+p.toFixed(1)+'<sup>'+k+'</sup>·'+(1-p).toFixed(1)+'<sup>'+(n-k)+'</sup> = <strong>'+ps[k].toFixed(5)+'</strong><br>E[X]=np=<strong>'+mean.toFixed(2)+'</strong>, Var(X)=np(1-p)=<strong>'+(n*p*(1-p)).toFixed(2)+'</strong>.';} host.querySelectorAll('input').forEach(function(e){e.addEventListener('input',draw);}); host.querySelector('[data-draw]').onclick=draw; draw(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="binomial-distribution"]').forEach(mount); });
}());
